const express = require('express');
const morgan = require('morgan');
const fs = require('fs');
const path = require('path');

const app = express();
const port = 3000;

// Create a write stream for logging
const accessLogStream = fs.createWriteStream(path.join(__dirname, 'access.log'), { flags: 'a' });

// Define a custom token for logging user information
morgan.token('username', (req) => req.headers['username'] || 'unknown');
morgan.token('ip', (req) => req.headers['x-forwarded-for'] || req.connection.remoteAddress);
morgan.token('custom-header', (req) => req.headers['custom-header'] || 'none');

// Create a combined log format that includes the custom tokens
app.use(morgan(':method :url :status :res[content-length] - :response-time ms :username :ip :custom-header', { stream: accessLogStream }));

app.use(express.json());

app.post('/submit', (req, res) => {
  const userSubmission = req.body.data;
  fs.appendFile('user-submissions.log', `User Data: ${userSubmission}\n`, err => {
    if (err) {
      console.error('Could not write user submission to log file', err);
      return res.status(500).send('Internal Server Error');
    }
    res.send('Data received and logged');
  });
});

app.listen(port, () => {
  console.log(`Server is running on port ${port}`);
});